import React, { useState, useEffect } from 'react';

const API = 'http://localhost:5000';

export default function Units() {
  const [units,    setUnits]   = useState([]);
  const [loading,  setLoading] = useState(true);
  const [toast,    setToast]   = useState(null);
  const [showForm, setShowForm] = useState(false);
  const [editing,  setEditing]  = useState(null);   // unit being edited, or null
  const [form,     setForm]     = useState({ code:'', name:'', lecturer:'' });
  const [saving,   setSaving]   = useState(false);

  const showToast = (msg, type='success') => {
    setToast({msg, type});
    setTimeout(() => setToast(null), 4000);
  };

  const load = async () => {
    setLoading(true);
    try {
      const r = await fetch(`${API}/api/units`);
      const d = await r.json();
      setUnits(Array.isArray(d) ? d : []);
    } catch { showToast('Could not load units', 'error'); }
    finally { setLoading(false); }
  };

  useEffect(() => { load(); }, []);

  const openAdd = () => {
    setEditing(null);
    setForm({ code:'', name:'', lecturer:'' });
    setShowForm(true);
  };

  const openEdit = (unit) => {
    setEditing(unit);
    setForm({ code: unit.code, name: unit.name, lecturer: unit.lecturer || '' });
    setShowForm(true);
  };

  const cancelForm = () => {
    setShowForm(false);
    setEditing(null);
    setForm({ code:'', name:'', lecturer:'' });
  };

  const handleSave = async () => {
    if (!form.code.trim() || !form.name.trim()) {
      showToast('Unit code and name are required', 'error'); return;
    }
    setSaving(true);
    try {
      const url    = editing ? `${API}/api/units/${editing.id}` : `${API}/api/units`;
      const method = editing ? 'PUT' : 'POST';
      const res    = await fetch(url, {
        method, headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(form)
      });
      const d = await res.json();
      if (!res.ok) { showToast(d.error || 'Failed to save', 'error'); return; }
      showToast(editing ? `Unit updated!` : d.message);
      cancelForm();
      load();
    } catch { showToast('Network error', 'error'); }
    finally { setSaving(false); }
  };

  const handleDelete = async (unit) => {
    if (!window.confirm(`Delete unit "${unit.name}"?\nStudents registered under this unit will not be affected.`)) return;
    try {
      await fetch(`${API}/api/units/${unit.id}`, { method: 'DELETE' });
      showToast(`"${unit.name}" deleted`);
      load();
    } catch { showToast('Failed to delete', 'error'); }
  };

  return (
    <div className="page-wide">
      <h1 className="page-title">Course Units</h1>
      <p className="page-sub">Manage course units available for attendance sessions and student registration.</p>

      {/* Stats */}
      <div className="stats">
        <div className="stat">
          <div className="stat-val" style={{color:'var(--accent)'}}>{units.length}</div>
          <div className="stat-lbl">Total Units</div>
        </div>
        <div className="stat">
          <div className="stat-val" style={{color:'var(--purple)'}}>
            {[...new Set(units.map(u => u.lecturer).filter(Boolean))].length}
          </div>
          <div className="stat-lbl">Lecturers</div>
        </div>
        <div className="stat">
          <div className="stat-val" style={{color:'var(--yellow)'}}>
            {new Date().getFullYear()}
          </div>
          <div className="stat-lbl">Academic Year</div>
        </div>
      </div>

      {/* Add form / Edit form */}
      {showForm && (
        <div className="panel" style={{border:'1px solid rgba(0,212,170,.25)',marginBottom:24}}>
          <div className="panel-title">
            {editing ? '✏️ Edit Unit' : '➕ Add New Unit'}
          </div>

          <div className="form-grid">
            <div className="form-group">
              <label>Unit Code *</label>
              <input
                value={form.code}
                onChange={e => setForm({...form, code: e.target.value})}
                placeholder="e.g. CS301, SE204, IT102"
              />
            </div>
            <div className="form-group">
              <label>Unit Name *</label>
              <input
                value={form.name}
                onChange={e => setForm({...form, name: e.target.value})}
                placeholder="e.g. Software Engineering, Data Structures"
              />
            </div>
            <div className="form-group full">
              <label>Lecturer Name</label>
              <input
                value={form.lecturer}
                onChange={e => setForm({...form, lecturer: e.target.value})}
                placeholder="e.g. Dr. Jane Wanjiru"
              />
            </div>
          </div>

          <div style={{display:'flex', gap:10, marginTop:8}}>
            <button className="btn btn-primary" onClick={handleSave} disabled={saving} style={{flex:1,justifyContent:'center'}}>
              {saving ? '⏳ Saving…' : editing ? '💾 Save Changes' : '✓ Add Unit'}
            </button>
            <button className="btn btn-secondary" onClick={cancelForm}>✕ Cancel</button>
          </div>
        </div>
      )}

      {/* Units table */}
      <div className="panel">
        <div style={{display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:20}}>
          <div className="panel-title" style={{marginBottom:0}}>📚 All Units</div>
          {!showForm && (
            <button className="btn btn-primary" onClick={openAdd} style={{padding:'8px 18px'}}>
              ➕ Add Unit
            </button>
          )}
        </div>

        {loading ? (
          <p style={{textAlign:'center', color:'var(--text2)', padding:'40px 0'}}>Loading…</p>
        ) : units.length === 0 ? (
          <div style={{textAlign:'center', padding:'48px 0'}}>
            <div style={{fontSize:48, marginBottom:16}}>📚</div>
            <p style={{color:'var(--text2)', fontSize:15, marginBottom:20}}>No units added yet</p>
            <button className="btn btn-primary" onClick={openAdd}>➕ Add Your First Unit</button>
          </div>
        ) : (
          <div className="table-wrap">
            <table>
              <thead>
                <tr>
                  <th>Unit Code</th>
                  <th>Unit Name</th>
                  <th>Lecturer</th>
                  <th>Added</th>
                  <th></th>
                </tr>
              </thead>
              <tbody>
                {units.map(u => (
                  <tr key={u.id}>
                    <td>
                      <span style={{
                        background:'rgba(124,106,247,.12)', color:'var(--purple)',
                        padding:'3px 10px', borderRadius:20,
                        fontSize:12, fontWeight:700, fontFamily:'monospace',
                      }}>{u.code}</span>
                    </td>
                    <td style={{fontWeight:600, color:'var(--text)'}}>{u.name}</td>
                    <td style={{color:'var(--text2)'}}>{u.lecturer || <span style={{color:'var(--text3)'}}>—</span>}</td>
                    <td style={{color:'var(--text3)', fontSize:'.8rem'}}>
                      {u.createdAt ? new Date(u.createdAt).toLocaleDateString() : '—'}
                    </td>
                    <td>
                      <div style={{display:'flex', gap:8}}>
                        <button
                          className="btn btn-secondary"
                          style={{padding:'5px 12px', fontSize:'.8rem'}}
                          onClick={() => openEdit(u)}
                        >
                          ✏️ Edit
                        </button>
                        <button
                          className="btn btn-danger"
                          style={{padding:'5px 12px', fontSize:'.8rem'}}
                          onClick={() => handleDelete(u)}
                        >
                          Remove
                        </button>
                      </div>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>

      {/* Info box */}
      <div className="panel" style={{background:'rgba(124,106,247,.05)', border:'1px solid rgba(124,106,247,.15)', marginTop:16}}>
        <div className="panel-title" style={{color:'var(--purple)', marginBottom:8}}>💡 How Units Work</div>
        <ul style={{paddingLeft:16, color:'var(--text2)', fontSize:'.85rem', lineHeight:1.9}}>
          <li>Units added here appear in the <strong>Course / Programme</strong> dropdown when registering students</li>
          <li>When taking attendance, the lecturer selects the unit — only students in that unit are recognized</li>
          <li>The unit name is used as the course label in Excel exports and attendance logs</li>
          <li>Deleting a unit does not remove students already registered under it</li>
        </ul>
      </div>

      {toast && <div className={`toast ${toast.type}`} onClick={() => setToast(null)}>{toast.msg}</div>}
    </div>
  );
}
